// Quiz actions
type QuizAction =
  | { type: "INITIALIZE_QUIZ"; payload: { questionCount: number } }
  | { type: "SELECT_ANSWER"; payload: string }
  | { type: "SUBMIT_ANSWER"; payload: { isCorrect: boolean } }
  | { type: "NEXT_QUESTION" }
