  | { type: "FINISH_QUIZ" }
  | { type: "RESTART_QUIZ"; payload: { questionCount: number } }
  | { type: "TOGGLE_USER_SENTENCES"; payload: number }
  | { type: "SET_QUESTION_START_TIME"; payload: number }
  | {
