+interface SentenceFeedback {
+  correct: boolean;
+  exampleSentence: string;
+  aiResponse: string;
+  hint: string;
+}
+
+interface VocabsFormASentencePracticeProps {
+  onBackToPracticeSelection?: () => void;
+}
+
+interface SentenceState {
+  currentQuestionIndex: number;
+  userSentence: string;
+  showResult: boolean;
+  score: number;
+  answeredQuestions: boolean[];
+  userAnswers: string[];
+  isSentencePracticeComplete: boolean;
+  showUserSentences: { [key: number]: boolean };
+  questionStartTime: number;
+  restartKey: number;
+  isSubmitting: boolean;
+  feedbackByQuestion: { [key: number]: SentenceFeedback };
+}
+
+type SentenceAction =
+  | { type: "INITIALIZE_SENTENCES"; payload: { questionCount: number } }
+  | { type: "UPDATE_SENTENCE"; payload: string }
+  | { type: "START_SUBMISSION" }
+  | {
+      type: "SUBMIT_SENTENCE";
+      payload: { sentence: string; feedback: SentenceFeedback };
+    }
+  | { type: "NEXT_QUESTION" }
+  | { type: "PREVIOUS_QUESTION" }
+  | { type: "FINISH_PRACTICE" }
+  | { type: "RESTART_PRACTICE"; payload: { questionCount: number } }
+  | { type: "TOGGLE_USER_SENTENCES"; payload: number }
+  | { type: "SET_QUESTION_START_TIME"; payload: number }
+  | {
+      type: "LOAD_QUESTION_STATE";
+      payload: { userSentence: string; showResult: boolean };
+    };
+
+const initialSentenceState: SentenceState = {
+  currentQuestionIndex: 0,
+  userSentence: "",
+  showResult: false,
+  score: 0,
+  answeredQuestions: [],
+  userAnswers: [],
+  isSentencePracticeComplete: false,
+  showUserSentences: {},
+  questionStartTime: Date.now(),
+  restartKey: 0,
+  isSubmitting: false,
+  feedbackByQuestion: {},
+};
+
+function sentenceReducer(
+  state: SentenceState,
+  action: SentenceAction
+): SentenceState {
+  switch (action.type) {
+    case "INITIALIZE_SENTENCES":
+      return {
+        ...state,
+        answeredQuestions: new Array(action.payload.questionCount).fill(false),
+        userAnswers: new Array(action.payload.questionCount).fill(""),
+        questionStartTime: Date.now(),
+        feedbackByQuestion: {},
+      };
+
+    case "UPDATE_SENTENCE":
+      return {
+        ...state,
+        userSentence: action.payload,
+      };
+
+    case "START_SUBMISSION":
+      return {
+        ...state,
+        isSubmitting: true,
+      };
+
+    case "SUBMIT_SENTENCE": {
+      const answeredQuestions = [...state.answeredQuestions];
+      const userAnswers = [...state.userAnswers];
+      const feedbackByQuestion = { ...state.feedbackByQuestion };
+      const isNewAnswer = !answeredQuestions[state.currentQuestionIndex];
+
+      answeredQuestions[state.currentQuestionIndex] = true;
+      userAnswers[state.currentQuestionIndex] = action.payload.sentence;
+      feedbackByQuestion[state.currentQuestionIndex] = action.payload.feedback;
+
+      return {
+        ...state,
+        showResult: true,
+        isSubmitting: false,
+        score:
+          isNewAnswer && action.payload.feedback.correct
+            ? state.score + 1
+            : state.score,
+        answeredQuestions,
+        userAnswers,
+        feedbackByQuestion,
+      };
+    }
+
+    case "NEXT_QUESTION":
+      if (state.currentQuestionIndex + 1 >= state.answeredQuestions.length) {
+        return {
+          ...state,
+          isSentencePracticeComplete: true,
+        };
+      }
+
+      return {
+        ...state,
+        currentQuestionIndex: state.currentQuestionIndex + 1,
+        questionStartTime: Date.now(),
+      };
+
+    case "PREVIOUS_QUESTION":
+      if (state.currentQuestionIndex === 0) return state;
+
+      return {
+        ...state,
+        currentQuestionIndex: state.currentQuestionIndex - 1,
+        questionStartTime: Date.now(),
+      };
+
+    case "FINISH_PRACTICE":
+      return {
+        ...state,
+        isSentencePracticeComplete: true,
+      };
+
+    case "RESTART_PRACTICE":
+      return {
+        currentQuestionIndex: 0,
+        userSentence: "",
+        showResult: false,
+        score: 0,
+        answeredQuestions: new Array(action.payload.questionCount).fill(false),
+        userAnswers: new Array(action.payload.questionCount).fill(""),
+        isSentencePracticeComplete: false,
+        showUserSentences: {},
+        questionStartTime: Date.now(),
+        restartKey: Date.now(),
+        isSubmitting: false,
+        feedbackByQuestion: {},
+      };
+
+    case "TOGGLE_USER_SENTENCES":
+      return {
+        ...state,
+        showUserSentences: {
+          ...state.showUserSentences,
+          [action.payload]: !state.showUserSentences[action.payload],
+        },
+      };
+
+    case "SET_QUESTION_START_TIME":
+      return {
+        ...state,
+        questionStartTime: action.payload,
+      };
+
+    case "LOAD_QUESTION_STATE":
+      return {
+        ...state,
+        userSentence: action.payload.userSentence,
+        showResult: action.payload.showResult,
+      };
+
+    default:
+      return state;
+  }
+}
+
+const escapeRegExp = (value: string) =>
+  value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
+
+const hasVocabularyWord = (sentence: string, word: string) => {
+  return new RegExp(`\\b${escapeRegExp(word)}\\b`, "i").test(sentence);
+};
+
+const countWords = (sentence: string) => {
+  return sentence.match(/[A-Za-z']+/g)?.length ?? 0;
+};
+
+const evaluateSentenceLocally = (
+  sentence: string,
+  word: VocabularyWord
+): SentenceFeedback => {
+  const trimmedSentence = sentence.trim();
+  const usesWord = hasVocabularyWord(trimmedSentence, word.word);
+  const wordCount = countWords(trimmedSentence);
+
+  if (!usesWord) {
+    return {
+      correct: false,
+      exampleSentence: word.example,
+      aiResponse: `Your sentence needs to use "${word.word}" as a complete word.`,
+      hint: `Try writing a full sentence that includes "${word.word}" and shows its meaning.`,
+    };
+  }
+
+  if (wordCount < 5) {
+    return {
+      correct: false,
+      exampleSentence: word.example,
+      aiResponse:
+        "This uses the vocabulary word, but it is too short to show clear meaning in context.",
+      hint: "Add more context so the sentence shows what the word means.",
+    };
+  }
+
+  return {
+    correct: true,
+    exampleSentence: word.example,
+    aiResponse:
+      "This sentence uses the vocabulary word in a complete context. AI feedback was unavailable, so a basic local check was used.",
+    hint: "For stronger practice, make sure the surrounding context clearly signals the word's meaning.",
+  };
+};
+
+export default function VocabsFormaSentencePractice({
+  onBackToPracticeSelection,
+}: VocabsFormASentencePracticeProps = {}) {
+  const [sentenceState, dispatch] = useReducer(
+    sentenceReducer,
+    initialSentenceState
+  );
+
+  const [vocabsData, setVocabsData] = useLocalStorage<VocabsData>(
+    "vocabsData",
+    {
+      learntVocabs: [],
+      userSentences: {},
+    }
+  );
+
+  const [practicePerformance, setPracticePerformance] =
+    useLocalStorage<PracticePerformanceData>("practicePerformanceData", {
+      attempts: [],
+      wordPerformance: {},
+      lastUpdated: Date.now(),
+      totalQuizzesTaken: 0,
+      overallAccuracy: 0,
+      strongWords: [],
+      weakWords: [],
+      improvingWords: [],
+    });
+
+  const learnedWords = useMemo(() => {
+    return vocabs_database.filter((word) =>
+      vocabsData.learntVocabs.includes(word.word)
+    );
+  }, [vocabsData.learntVocabs]);
+
+  const sentenceQuestions = useMemo(() => {
+    if (learnedWords.length === 0) return [];
+
+    const categorizedWords = {
+      notPracticed: [] as VocabularyWord[],
+      struggling: [] as VocabularyWord[],
+      learning: [] as VocabularyWord[],
+      proficient: [] as VocabularyWord[],
+      mastered: [] as VocabularyWord[],
+    };
+
+    learnedWords.forEach((word) => {
+      const performance = practicePerformance.wordPerformance[word.word];
+
+      if (!performance) {
+        categorizedWords.notPracticed.push(word);
+        return;
+      }
+
+      categorizedWords[performance.masteryLevel].push(word);
+    });
+
+    Object.keys(categorizedWords).forEach((key) => {
+      categorizedWords[key as keyof typeof categorizedWords].sort(
+        () => Math.random() - 0.5
+      );
+    });
+
+    return [
+      ...categorizedWords.notPracticed,
+      ...categorizedWords.struggling,
+      ...categorizedWords.learning,
+      ...categorizedWords.proficient,
+      ...categorizedWords.mastered,
+    ].map((word) => ({ word }));
+  }, [learnedWords, sentenceState.restartKey]);
+
+  useEffect(() => {
+    dispatch({
+      type: "INITIALIZE_SENTENCES",
+      payload: { questionCount: sentenceQuestions.length },
