+type ChatTask = "validate-user-definition" | "validate-user-sentence";
+
+type ValidationResult = {
+  correct: boolean;
+  exampleSentence: string;
+  aiResponse: string;
+  hint: string;
+};
+
+type ChatRequestBody = {
+  message?: unknown;
+  task?: unknown;
+  data?: unknown;
+};
+
+type RequestData = Record<string, unknown>;
+
+const supportedTasks = new Set<ChatTask>([
+  "validate-user-definition",
+  "validate-user-sentence",
+]);
+
+const getString = (data: RequestData, key: string) => {
+  const value = data[key];
+  return typeof value === "string" ? value.trim() : "";
+};
+
+const failureResponse = (message: string, status: number) => {
+  return NextResponse.json({ success: false, message }, { status });
+};
+
+const parseData = (data: unknown): RequestData => {
+  if (!data || typeof data !== "object" || Array.isArray(data)) return {};
+  return data as RequestData;
+};
+
+const extractJsonObject = (text: string): unknown => {
+  const fencedMatch = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
+  const jsonText = fencedMatch?.[1] ?? text;
+  const firstBrace = jsonText.indexOf("{");
+  const lastBrace = jsonText.lastIndexOf("}");
+
+  if (firstBrace === -1 || lastBrace === -1 || lastBrace <= firstBrace) {
+    throw new Error("AI response did not include a JSON object.");
+  }
+
+  return JSON.parse(jsonText.slice(firstBrace, lastBrace + 1));
+};
+
+const normalizeValidationResult = (value: unknown): ValidationResult => {
+  const result =
+    value &&
+    typeof value === "object" &&
+    "result" in value &&
+    typeof (value as { result?: unknown }).result === "object"
+      ? (value as { result: unknown }).result
+      : value;
+
+  if (!result || typeof result !== "object" || Array.isArray(result)) {
+    throw new Error("AI response JSON was not an object.");
+  }
+
+  const resultData = result as Record<string, unknown>;
+
+  if (typeof resultData.correct !== "boolean") {
+    throw new Error("AI response JSON is missing a boolean correct field.");
+  }
+
+  return {
+    correct: resultData.correct,
+    exampleSentence:
+      typeof resultData.exampleSentence === "string"
+        ? resultData.exampleSentence
+        : "",
+    aiResponse:
+      typeof resultData.aiResponse === "string" ? resultData.aiResponse : "",
+    hint: typeof resultData.hint === "string" ? resultData.hint : "",
+  };
+};
+
+const buildDefinitionPrompt = (data: RequestData, message: string) => {
+  const word = getString(data, "word");
+  const userDefinition = getString(data, "userDefinition") || message;
+  const correctDefinition = getString(data, "correctDefinition");
+  const exampleSentence = getString(data, "exampleSentence");
+
+  if (!word || !userDefinition || !correctDefinition) {
+    return null;
+  }
+
+  return `Evaluate this learner-written definition for an SAT vocabulary word.
+
+Word: ${word}
+Correct definition: ${correctDefinition}
+Learner definition: ${userDefinition}
+Example sentence: ${exampleSentence}
+
+Return only JSON with these exact fields:
+{
+  "correct": boolean,
+  "exampleSentence": string,
+  "aiResponse": string,
+  "hint": string
+}
+
+Mark correct when the learner captures the core meaning, even if wording differs. The aiResponse should be concise, encouraging tutor feedback.`;
+};
+
+const buildSentencePrompt = (data: RequestData, message: string) => {
+  const word = getString(data, "word");
+  const userSentence = getString(data, "userSentence") || message;
+  const correctDefinition = getString(data, "correctDefinition");
+  const exampleSentence = getString(data, "exampleSentence");
+  const partOfSpeech = getString(data, "partOfSpeech");
+
+  if (!word || !userSentence || !correctDefinition) {
+    return null;
+  }
+
+  return `Evaluate this learner-written sentence for an SAT vocabulary word.
+
+Word: ${word}
+Part of speech: ${partOfSpeech}
+Definition: ${correctDefinition}
+Learner sentence: ${userSentence}
+Reference example: ${exampleSentence}
+
+Return only JSON with these exact fields:
+{
+  "correct": boolean,
+  "exampleSentence": string,
+  "aiResponse": string,
+  "hint": string
+}
+
+Mark correct only if the sentence uses the target word naturally as a complete word and the context fits the definition. The aiResponse should be concise tutor feedback. If incorrect, give one actionable revision hint.`;
+};
+
+export async function POST(request: NextRequest) {
+  let body: ChatRequestBody;
+
+  try {
+    body = await request.json();
+  } catch {
+    return failureResponse("Request body must be valid JSON.", 400);
+  }
+
+  if (typeof body.task !== "string" || !body.task.trim()) {
+    return failureResponse(
