+    task === "validate-user-definition"
+      ? buildDefinitionPrompt(data, message)
+      : buildSentencePrompt(data, message);
+
+  if (!prompt) {
+    return failureResponse(`Missing required data for task: ${task}.`, 400);
+  }
+
+  const apiKey = process.env.OPENROUTER_KEY;
+
+  if (!apiKey) {
+    return failureResponse("AI feedback is not configured.", 503);
+  }
+
+  try {
+    const openrouter = createOpenRouter({ apiKey });
+    const { text } = await generateText({
+      model: openrouter(process.env.OPENROUTER_MODEL || "openai/gpt-4o-mini"),
+      system:
+        "You are a precise vocabulary tutor. Return only valid JSON and no markdown.",
+      prompt,
+      temperature: 0.2,
+      maxOutputTokens: 400,
+    });
+
+    const result = normalizeValidationResult(extractJsonObject(text));
+
+    return NextResponse.json({
+      success: true,
+      result,
+    });
+  } catch (error) {
+    console.error("Vocabulary chat route error:", error);
+    return failureResponse("Unable to generate AI feedback.", 502);
+  }
