    54	const normalizeValidationResult = (value: unknown): ValidationResult => {
    55	  const result =
    56	    value &&
    57	    typeof value === "object" &&
    58	    "result" in value &&
    59	    typeof (value as { result?: unknown }).result === "object"
    60	      ? (value as { result: unknown }).result
    61	      : value;
    62	
    63	  if (!result || typeof result !== "object" || Array.isArray(result)) {
    64	    throw new Error("AI response JSON was not an object.");
    65	  }
    66	
    67	  const resultData = result as Record<string, unknown>;
    68	
    69	  if (typeof resultData.correct !== "boolean") {
    70	    throw new Error("AI response JSON is missing a boolean correct field.");
    71	  }
    72	
    73	  return {
    74	    correct: resultData.correct,
    75	    exampleSentence:
    76	      typeof resultData.exampleSentence === "string"
    77	        ? resultData.exampleSentence
    78	        : "",
    79	    aiResponse:
    80	      typeof resultData.aiResponse === "string" && resultData.aiResponse.trim()
    81	        ? resultData.aiResponse
    82	        : "Feedback was generated, but the response was missing a written explanation.",
    83	    hint:
    84	      typeof resultData.hint === "string" && resultData.hint.trim()
    85	        ? resultData.hint
    86	        : "Review the word meaning and revise with clearer context if needed.",
    87	  };
    88	};
