   148	export async function POST(request: NextRequest) {
   149	  let body: ChatRequestBody;
   150	
   151	  try {
   152	    body = await request.json();
   153	  } catch {
   154	    return failureResponse("Request body must be valid JSON.", 400);
   155	  }
   156	
   157	  if (typeof body.task !== "string" || !body.task.trim()) {
   158	    return failureResponse(
   159	      "Missing task. Supported tasks: validate-user-definition, validate-user-sentence.",
   160	      400
   161	    );
   162	  }
   163	
   164	  if (!supportedTasks.has(body.task as ChatTask)) {
   165	    return failureResponse(`Unsupported task: ${body.task}.`, 400);
   166	  }
   167	
   168	  const task = body.task as ChatTask;
   169	  const message = typeof body.message === "string" ? body.message.trim() : "";
   170	  const data = parseData(body.data);
   171	  const prompt =
   172	    task === "validate-user-definition"
   173	      ? buildDefinitionPrompt(data, message)
   174	      : buildSentencePrompt(data, message);
   175	
   176	  if (!prompt) {
   177	    return failureResponse(`Missing required data for task: ${task}.`, 400);
   178	  }
   179	
   180	  const apiKey = process.env.OPENROUTER_KEY;
   181	
   182	  if (!apiKey) {
   183	    return failureResponse("AI feedback is not configured.", 503);
   184	  }
   185	
   186	  try {
   187	    const openrouter = createOpenRouter({ apiKey });
   188	    const { text } = await generateText({
   189	      model: openrouter(process.env.OPENROUTER_MODEL || "openai/gpt-4o-mini"),
   190	      system:
   191	        "You are a precise vocabulary tutor. Return only valid JSON and no markdown.",
   192	      prompt,
   193	      temperature: 0.2,
   194	      maxOutputTokens: 400,
   195	    });
   196	
   197	    const result = normalizeValidationResult(extractJsonObject(text));
   198	
   199	    return NextResponse.json({
   200	      success: true,
   201	      result,
   202	    });
   203	  } catch (error) {
   204	    console.error("Vocabulary chat route error:", error);
   205	    return failureResponse("Unable to generate AI feedback.", 502);
   206	  }
   207	}
